#include<bits/stdc++.h>
using namespace std;
deque<int>dq;
int main(void){
	std::ios::sync_with_stdio(false);
	std::cin.tie(0);std::cout.tie(0);
    int n,c=1,k;
    char a,b;
    cin>>n;
    while(n--){
        cin>>a>>b;
        if(a=='A'&&b=='L')dq.push_front(c++);
        else if(a=='A')dq.push_back(c++);  
        else if(b=='L'){
            cin>>k;
            for(int j=0;j<k;j++)dq.pop_front();
        }else{
            cin>>k;
            for(int j=0;j<k;j++)dq.pop_back();
        }
    }
    while(!dq.empty())cout<<dq.front()<<'\n',dq.pop_front();
    return false;
}
